   public void setupAnim(Specter entity, float limbSwing, float limbSwingAmount, float ageInTicks, float netHeadYaw, float headPitch) {
      float headRot = netHeadYaw / (180F / (float)Math.PI);
      this.RightLeg.xRot = Mth.cos(limbSwing * 0.6F) * -0.6F * limbSwingAmount;
      this.LeftLeg.xRot = -this.RightLeg.xRot;
      this.RightFoot.xRot = this.RightLeg.xRot * 0.6F;
      this.LeftFoot.xRot = this.LeftLeg.xRot * 0.6F;
      this.Torso.yRot = headRot * 0.35F;
      this.Head.yRot = headRot * 0.8F;
      if (limbSwingAmount > -0.15F && limbSwingAmount < 0.15F) {
         float value = Mth.sin(ageInTicks / 6.0F) / 5.0F;
         this.RightArm.yRot = value;
         this.RightForArm.yRot = this.RightArm.yRot * 0.6F;
         this.LeftArm.yRot = -value * 0.8F;
         this.LeftForArm.yRot = this.LeftArm.yRot * 0.6F;
      } else {
         float armM = Mth.sin(limbSwing * 0.4F) * 0.4F * limbSwingAmount;
         this.RightArm.xRot = armM * 0.5F;
         this.RightArm.yRot = armM;
         this.RightForArm.yRot = armM * 0.6F;
         this.LeftArm.xRot = -armM * 0.7F;
         this.LeftArm.yRot = armM * 0.8F;
         this.LeftForArm.yRot = this.LeftArm.yRot * 0.6F;
      }

      this.Jaw.xRot = Mth.sin(ageInTicks / 8.0F) / 6.0F;
      this.Jaw.yRot = Mth.sin(ageInTicks / 8.0F) / 8.0F;
      this.animateTentacleY(this.Tentacle1Seg1, Mth.sin(ageInTicks / 6.0F) / 6.0F);
      this.animateTentacleX(this.Tentacle1Seg1, Mth.sin(ageInTicks / 5.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle1Seg2, Mth.sin(ageInTicks / 6.0F) / 5.0F);
      this.animateTentacleZ(this.Tentacle1Seg3, Mth.sin(ageInTicks / 5.0F) / 4.0F);
      this.animateTentacleX(this.Tentacle2Seg1, Mth.sin(ageInTicks / 6.0F) / 6.0F);
      this.animateTentacleY(this.Tentacle2Seg1, Mth.cos(ageInTicks / 5.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle2Seg2, Mth.sin(ageInTicks / 7.0F) / 5.0F);
      this.animateTentacleZ(this.Tentacle2Seg3, Mth.cos(ageInTicks / 4.0F) / 4.0F);
      this.animateTentacleY(this.Tentacle3Seg1, Mth.cos(ageInTicks / 5.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle3Seg2, Mth.cos(ageInTicks / 5.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle3Seg3, Mth.cos(ageInTicks / 5.0F) / 3.0F);
      this.animateTentacleY(this.Tentacle4Seg1, Mth.sin(ageInTicks / 8.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle4Seg2, Mth.sin(ageInTicks / 7.0F) / 2.0F);
      this.animateTentacleZ(this.Tentacle4Seg3, Mth.cos(ageInTicks / 6.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle5Seg1, Mth.cos(ageInTicks / 5.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle5Seg2, Mth.sin(ageInTicks / 6.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle5Seg3, Mth.sin(ageInTicks / 6.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle6Seg1, Mth.cos(ageInTicks / 8.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle6Seg2, Mth.cos(ageInTicks / 8.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle6Seg3, Mth.cos(ageInTicks / 8.0F) / 4.0F);
      this.animateTentacleX(this.Tentacle7Seg1, Mth.cos(ageInTicks / 6.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle7Seg2, Mth.cos(ageInTicks / 5.0F) / 4.0F);
      this.animateTentacleZ(this.Tentacle7Seg3, Mth.cos(ageInTicks / 5.0F) / 4.0F);
      this.animateTentacleX(this.Tentacle8Seg1, Mth.cos(ageInTicks / 6.0F) / 3.0F);
      this.animateTentacleX(this.Tentacle8Seg2, Mth.cos(ageInTicks / 5.0F) / 5.0F);
      this.animateTentacleX(this.Tentacle8Seg3, Mth.cos(ageInTicks / 7.0F) / 4.0F);
      this.animateTentacleX(this.Tentacle9Seg1, Mth.sin(ageInTicks / 6.0F) / 3.0F);
      this.animateTentacleZ(this.Tentacle9Seg2, Mth.cos(ageInTicks / 5.0F) / 5.0F);
      this.animateTentacleZ(this.Tentacle9Seg3, Mth.cos(ageInTicks / 7.0F) / 4.0F);
      this.animateTumor(this.Tumor1, Mth.cos(ageInTicks / 8.0F) / 10.0F);
      this.animateTumor(this.Tumor2, Mth.sin(ageInTicks / 7.0F) / 10.0F);
   }

